using namespace std;

int main() {
    int a = 5;
    cout << "a = " << a << endl;

    a++;
    cout << "a++ 后: " << a << endl;

    ++a;
    cout << "++a 后: " << a << endl;

    int b = 5;
    int x = b++;
    cout << "x = b++ : x=" << x << ", b=" << b << endl;

    int c = 5;
    int y = ++c;
    cout << "y = ++c : y=" << y << ", c=" << c << endl;

    int d = 10;
    d--;
    cout << "d-- 后: " << d << endl;

    return 0;
}

